import{_ as o,o as a,c as r,ae as e}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"바이브 코딩이란?","description":"","frontmatter":{},"headers":[],"relativePath":"part1-opening/index.md","filePath":"part1-opening/index.md"}'),n={name:"part1-opening/index.md"};function d(i,t,l,s,p,h){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="바이브-코딩이란" tabindex="-1">바이브 코딩이란? <a class="header-anchor" href="#바이브-코딩이란" aria-label="Permalink to &quot;바이브 코딩이란?&quot;">​</a></h1><blockquote><p>&quot;코딩의 분위기에 몸을 맡기고, 지수적으로 발전하는 LLM에게 코드를 맡기면 된다. 코드가 실제로 작동하는지만 보면 되고, 코드를 읽을 일은 거의 없다.&quot;</p><p>— <strong>Andrej Karpathy</strong>, 2025년 2월</p></blockquote><h2 id="바이브-코딩의-정의" tabindex="-1">바이브 코딩의 정의 <a class="header-anchor" href="#바이브-코딩의-정의" aria-label="Permalink to &quot;바이브 코딩의 정의&quot;">​</a></h2><p><strong>바이브 코딩(Vibe Coding)</strong>이란, 사람이 자연어로 원하는 기능을 설명하면 AI가 코드를 생성하는 새로운 개발 패러다임입니다.</p><p>기존 개발 방식과의 차이를 비교해보면:</p><table tabindex="0"><thead><tr><th>구분</th><th>전통적 코딩</th><th>바이브 코딩</th></tr></thead><tbody><tr><td>입력</td><td>프로그래밍 언어</td><td>자연어(한국어, 영어 등)</td></tr><tr><td>주체</td><td>사람이 직접 코드 작성</td><td>AI가 코드 생성, 사람이 검토</td></tr><tr><td>필요 역량</td><td>문법, 알고리즘, 프레임워크 지식</td><td>문제 정의, 요구사항 전달 능력</td></tr><tr><td>속도</td><td>시간~일 단위</td><td>분~시간 단위</td></tr></tbody></table><h2 id="왜-바이브-인가" tabindex="-1">왜 &quot;바이브&quot;인가? <a class="header-anchor" href="#왜-바이브-인가" aria-label="Permalink to &quot;왜 &quot;바이브&quot;인가?&quot;">​</a></h2><p>Karpathy가 사용한 &quot;vibe&quot;라는 단어는 의도적입니다:</p><ul><li>코드의 세부 문법에 집착하지 않고</li><li>AI에게 <strong>분위기(vibe)</strong>를 전달하면</li><li>AI가 알아서 구현해준다</li></ul><p>즉, 개발의 초점이 <strong>&quot;어떻게(How) 코드를 짤 것인가&quot;</strong>에서 <strong>&quot;무엇을(What) 만들 것인가&quot;</strong>로 이동한 것입니다.</p><h2 id="이-워크숍에서-배울-것" tabindex="-1">이 워크숍에서 배울 것 <a class="header-anchor" href="#이-워크숍에서-배울-것" aria-label="Permalink to &quot;이 워크숍에서 배울 것&quot;">​</a></h2><p>이 워크숍에서는 바이브 코딩이 단순한 유행어가 아니라, <strong>3세대에 걸쳐 진화한 엔지니어링 분야</strong>임을 이해하게 됩니다:</p><ol><li><strong>1세대 — 프롬프트 엔지니어링</strong>: AI에게 잘 물어보는 기술</li><li><strong>2세대 — 컨텍스트 엔지니어링</strong>: AI에게 맥락을 심어주는 기술</li><li><strong>3세대 — 하네스 엔지니어링</strong>: AI 팀을 구성하고 협업시키는 기술</li></ol><p>그리고 3세대 하네스 엔지니어링의 대표 도구인 <strong>oh-my-agent</strong>를 직접 실습합니다.</p>',14)])])}const c=o(n,[["render",d]]);export{g as __pageData,c as default};
